  username: string;
  realname: string;
  password: string;
  passwordSource: "env" | "passwordFile" | "config" | "none";
  config: IrcAccountConfig;
};

export type IrcAccountConfig = {
  name?: string;
  enabled?: boolean;
  host?: string;
  port?: number;
  tls?: boolean;
  nick?: string;
  // ... plus dmPolicy, allowFrom, groups, channels, etc.
  textChunkLimit?: number;
  chunkMode?: "length" | "newline";
}
```

### Nostr Account Type (`src/types.ts`)
```typescript
export interface ResolvedNostrAccount {
  accountId: string;
  name?: string;
  enabled: boolean;
  configured: boolean;
  privateKey: string;
  publicKey: string;
  relays: string[];
  profile?: NostrProfile;
  config: NostrAccountConfig;
}

export interface NostrAccountConfig {
  enabled?: boolean;
  name?: string;
  defaultAccount?: string;
  privateKey?: SecretInput;
  relays?: string[];
  dmPolicy?: "pairing" | "allowlist" | "open" | "disabled";
  allowFrom?: Array<string | number>;
  profile?: NostrProfile;
}
```

---

## CONFIG SCHEMAS

### IRC Config Schema (`src/config-schema.ts`)
Uses Zod validation:
- `IrcGroupSchema` - Group configuration with `requireMention`, `tools`, `allowFrom`
- `IrcAccountSchemaBase` - Base account config with host, port, tls, nick, nickserv, dmPolicy, allowFrom, groupPolicy, groups
- `IrcAccountSchema` - Full schema with validation superrefinements
- Exported as `IrcChannelConfigSchema`

### Nostr Config Schema (`src/config-schema.ts`)
Uses Zod validation:
- `NostrProfileSchema` - NIP-01 profile metadata
- `NostrConfigSchema` - Account config with privateKey, relays, dmPolicy, allowFrom, profile
- Built with `buildChannelConfigSchema()`
- Exported as `nostrChannelConfigSchema`

---

## ACCOUNT RESOLUTION PATTERN

Both plugins export similar account resolution functions:

### IRC (`src/accounts.ts`)
```typescript
export function resolveIrcAccount(opts: {
  cfg: CoreConfig;
  accountId?: string;
}): ResolvedIrcAccount { ... }

export function listIrcAccountIds(cfg: CoreConfig): string[] { ... }
export function resolveDefaultIrcAccountId(cfg: CoreConfig): string { ... }
```

### Nostr (`src/types.ts`)
```typescript
export function resolveNostrAccount(opts: {
  cfg: OpenClawConfig;
  accountId?: string | null;
}): ResolvedNostrAccount { ... }

export function listNostrAccountIds(cfg: OpenClawConfig): string[] { ... }
export function resolveDefaultNostrAccountId(cfg: OpenClawConfig): string { ... }
```

---

## MESSAGE SENDING

### IRC (`src/send.ts`)
```typescript
export async function sendMessageIrc(
  to: string,
  text: string,
  opts: SendIrcOptions = {},
): Promise<SendIrcResult> {
  // opts: { cfg?, accountId?, replyTo?, target?, client? }
  // Connects to IRC server, sends PRIVMSG
  // Records outbound activity via runtime
}
```

### Nostr (`src/channel.ts`)
```typescript
sendText: async ({ cfg, to, text, accountId }) => {
  const bus = activeBuses.get(aid);
  const tableMode = core.channel.text.resolveMarkdownTableMode({...});
  const message = core.channel.text.convertMarkdownTables(text, tableMode);
  await bus.sendDm(normalizedTo, message);
  return attachChannelToResult("nostr", {...});
}
```

**Pattern**: Both use `attachChannelToResult()` to attach channel metadata to outbound results.

---

## RUNTIME INITIALIZATION

### IRC (`src/runtime.ts`)
```typescript
const { setRuntime: setIrcRuntime, getRuntime: getIrcRuntime } =
  createPluginRuntimeStore<PluginRuntime>("IRC runtime not initialized");
export { getIrcRuntime, setIrcRuntime };
```

### Nostr (`src/runtime.ts`)
```typescript
const { setRuntime: setNostrRuntime, getRuntime: getNostrRuntime } =
  createPluginRuntimeStore<PluginRuntime>("Nostr runtime not initialized");
export { getNostrRuntime, setNostrRuntime };
```

**Both use**: `createPluginRuntimeStore()` from `"openclaw/plugin-sdk/runtime-store"`

---

## GATEWAY/CHANNEL STARTUP

### IRC (`src/channel.ts`)
```typescript
gateway: {
  startAccount: async (ctx) => {
    if (!account.configured) {
      throw new Error(`IRC is not configured...`);
    }
    await runStoppablePassiveMonitor({
      abortSignal: ctx.abortSignal,
      start: async () =>
        await monitorIrcProvider({
          accountId: account.accountId,
          config: ctx.cfg,
          runtime: ctx.runtime,
          abortSignal: ctx.abortSignal,
          statusSink,
        }),
    });
  },
}
```

### Nostr (`src/channel.ts`)
```typescript
gateway: {
  startAccount: async (ctx) => {
    const pairing = createChannelPairingController({...});
    const bus = await startNostrBus({
      accountId: account.accountId,
      privateKey: account.privateKey,
      relays: account.relays,
      authorizeSender: async ({...}) => {...},
      onMessage: async (senderPubkey, text, reply, meta) => {
        await dispatchInboundDirectDmWithRuntime({...});
      },
      // ... callbacks for errors, connect, disconnect, metrics
    });
    activeBuses.set(account.accountId, bus);
    return { stop: () => { bus.close(); } };
  },
}
```

**Key pattern**: Gateway startup receives a context with `abortSignal` for cleanup and `setStatus` for status updates.

---

## SETUP & ONBOARDING

### Setup Entry Point (Both)
- `setup-entry.ts` - Defines CLI entry for setup
- `src/setup-surface.ts` or `src/setup-core.ts` - Implementation

### IRC Setup Pattern (`src/setup-core.ts`)
```typescript
export function updateIrcAccountConfig(
  cfg: CoreConfig,
  accountId: string,
  patch: Partial<IrcAccountConfig>,
): CoreConfig {
  return patchScopedAccountConfig({
    cfg,
    channelKey: "irc",
    accountId,
    patch,
  }) as CoreConfig;
}
```

### Nostr Setup Pattern (`src/setup-surface.ts`)
```typescript
const promptNostrAllowFrom = createTopLevelChannelParsedAllowFromPrompt({
  channel: "nostr",
  defaultAccountId: DEFAULT_ACCOUNT_ID,
  parseEntries: parseNostrAllowFrom,
  mergeEntries: ({ existing, parsed }) => mergeAllowFromEntries(existing, parsed),
});

const nostrSetupWizard: ChannelSetupWizard = {
  // Interactive prompts for setup
};
```

---

## INBOUND MESSAGE HANDLING

### IRC Pattern (`src/inbound.ts`)
```typescript
export async function handleIrcInbound(params: {
  message: IrcInboundMessage;
  account: ResolvedIrcAccount;
  config: CoreConfig;
  runtime: RuntimeEnv;
  connectedNick?: string;
  sendReply?: (...) => Promise<void>;
  statusSink?: (...) => void;
}): Promise<void> {
  // Validates sender against allowlists
  // Checks DM vs group message type
  // Routes through pairing/policy checks
  // Dispatches to runtime
}
```

### Nostr Pattern (`src/channel.ts`)
```typescript
onMessage: async (senderPubkey, text, reply, meta) => {
  const resolvedAccess = await resolveNostrDirectAccess({
    cfg, accountId, dmPolicy, allowFrom, senderPubkey, rawBody: text
  });
  if (resolvedAccess.access.decision !== "allow") {
    return;
  }
  await dispatchInboundDirectDmWithRuntime({
    cfg, runtime, channel: "nostr",
    channelLabel: "Nostr",
    peer: { kind: "direct", id: senderPubkey },
    ...
  });
}
```

---

## MESSAGING TARGET NORMALIZATION

### IRC (`src/normalize.ts`)
- Normalizes targets: channels start with `#`, nicks are bare
- `normalizeIrcMessagingTarget()` validates target format
- `isChannelTarget()` distinguishes group vs direct

### Nostr (`src/channel.ts`)
```typescript
normalizeTarget: (target) => {
  const cleaned = target.trim().replace(/^nostr:/i, "");
  try {
    return normalizePubkey(cleaned);
  } catch {
    return cleaned;
  }
},
targetResolver: {
  looksLikeId: (input) => 
    input.trim().startsWith("npub1") || /^[0-9a-fA-F]{64}$/.test(input),
  hint: "<npub|hex pubkey|nostr:npub...>",
}
```

---

## SECURITY & DM POLICIES

Both plugins use similar pattern:

### IRC (`src/channel.ts`)
```typescript
const resolveIrcDmPolicy = createScopedDmSecurityResolver<ResolvedIrcAccount>({
  channelKey: "irc",
  resolvePolicy: (account) => account.config.dmPolicy,
  resolveAllowFrom: (account) => account.config.allowFrom,
  policyPathSuffix: "dmPolicy",
  normalizeEntry: (raw) => normalizeIrcAllowEntry(raw),
});

security: {
  resolveDmPolicy: resolveIrcDmPolicy,
  collectWarnings: collectIrcSecurityWarnings,
}
```

### Nostr (`src/channel.ts`)
```typescript
const resolveNostrDmPolicy = createScopedDmSecurityResolver<ResolvedNostrAccount>({
  channelKey: "nostr",
  resolvePolicy: (account) => account.config.dmPolicy,
  resolveAllowFrom: (account) => account.config.allowFrom,
  policyPathSuffix: "dmPolicy",
  defaultPolicy: "pairing",  // Nostr defaults to pairing
  normalizeEntry: (raw) => normalizePubkey(raw.trim().replace(/^nostr:/i, "")),
});
```

---

## KEY EXPORTS FOR EXTERNAL USE

### IRC (`api.ts`)
```typescript
export * from "./src/accounts.js";
export * from "./src/setup-surface.js";
```

### Nostr (`api.ts`)
```typescript
export * from "./runtime-api.js";  // Re-exports from plugin-sdk/nostr
```

---

## PATTERNS TO REPLICATE FOR A NEW PLUGIN

1. **Entry Point** (`index.ts`):
   - Call `defineChannelPluginEntry()`
   - Export `plugin` (from `src/channel.js`)
   - Export `setRuntime` (from `src/runtime.js`)
   - Optionally implement `registerFull(api)` for custom routes

2. **Channel Plugin** (`src/channel.ts`):
   - Call `createChatChannelPlugin()` with config object
   - Define `base` section with capabilities, setup, config schema, messaging, resolver, directory, status, gateway
   - Define `pairing` section with text-based pairing controller
   - Define `security` section with DM policy resolver and warning collectors
   - Define `outbound` section with delivery mode, text chunk limits, send handlers

3. **Types** (`src/types.ts`):
   - Create `ResolvedAccountType` interface with all runtime values
   - Create `AccountConfigType` interface with all config options
   - Export account resolution functions: `resolveAccount()`, `listAccountIds()`, `resolveDefaultAccountId()`

4. **Config Schema** (`src/config-schema.ts`):
   - Use Zod to define validation schema
   - Export as `ChannelConfigSchema`
   - Wrap with `buildChannelConfigSchema()`

5. **Runtime** (`src/runtime.ts`):
   - Use `createPluginRuntimeStore<PluginRuntime>()`
   - Export getter and setter functions

6. **Package Metadata** (`package.json`):
   - Set `"openclaw"` block with extensions, channel metadata, setupEntry
   - Include any external dependencies (nostr-tools, etc.)

7. **Chat Types & Text Limits**:
   - Set `capabilities.chatTypes` to `["direct"]` (DM-only) or `["direct", "group"]` (both)
   - Set `outbound.textChunkLimit` based on protocol limits (350 for IRC, 4000 for Nostr)

---

## KEY TECHNICAL DIFFERENCES

| Aspect | IRC | Nostr |
|--------|-----|-------|
| **Chat Types** | direct + group | direct only |
| **Text Chunk Limit** | 350 bytes | 4000 bytes |
| **Media Support** | Yes | No (MVP) |
| **Block Streaming** | Yes | No |
| **Account Config** | Per-account per-server | Single account (one privkey) |
| **Inbound Pattern** | Monitor-based (passive) | Bus-based (relay listening) |
| **Message Transport** | TCP/TLS socket | WebSocket relays (NIP-04 encrypted) |
| **Startup** | `runStoppablePassiveMonitor()` | `startNostrBus()` with event handlers |
| **Default DM Policy** | "pairing" | "pairing" |
| **Pairing** | Optional | Required by default |

---

This gives you everything needed to build a new channel plugin by following the same architectural patterns. The key is understanding the `createChatChannelPlugin()` structure and how account resolution, config schemas, and runtime initialization tie together.

