130	  formatAllowFrom: (allowFrom) =>
131	    allowFrom
132	      .map((entry) => String(entry).trim())
133	      .filter(Boolean)
134	      .map((entry) => {
135	        if (entry === "*") {
136	          return "*";
137	        }
138	        try {
139	          return normalizePubkey(entry);
140	        } catch {
141	          return entry;
142	        }
143	      })
144	      .filter(Boolean),
145	});
