91	export const nostrSetupAdapter: ChannelSetupAdapter = {
92	  resolveAccountId: () => DEFAULT_ACCOUNT_ID,
93	  applyAccountName: ({ cfg, name }) =>
94	    patchTopLevelChannelConfigSection({
95	      cfg,
96	      channel,
97	      patch: name?.trim() ? { name: name.trim() } : {},
98	    }),
99	  validateInput: ({ input }) => {
100	    const typedInput = input as {
