  let apiKey = pbCfg?.apiKey?.trim() ?? "";
  if (!apiKey && accountId === DEFAULT_ACCOUNT_ID) {
    apiKey = process.env.PULSEBOARD_API_KEY?.trim() ?? "";
  }

  const serverUrl =
    pbCfg?.serverUrl?.trim() ||
    process.env.PULSEBOARD_SERVER_URL?.trim() ||
    "https://api.pulseboard.example";

  const configured = Boolean(apiKey);

  return {
    accountId,
    name: pbCfg?.name?.trim() || undefined,
    enabled: baseEnabled,
    configured,
    apiKey,
    serverUrl,
    boards: pbCfg?.boards ?? [],
    config: {
      enabled: pbCfg?.enabled,
      name: pbCfg?.name,
      apiKey: pbCfg?.apiKey,
      serverUrl: pbCfg?.serverUrl,
      boards: pbCfg?.boards,
      dmPolicy: pbCfg?.dmPolicy,
      allowFrom: pbCfg?.allowFrom,
    },
  };
}

