/**
 * Target normalization for PulseBoard.
 *
 * Group targets (boards) are prefixed with `#` (e.g. `#general`).
 * Direct-message targets are bare usernames (e.g. `alice`).
 */

const PULSEBOARD_TARGET_PATTERN = /^[a-zA-Z0-9_][a-zA-Z0-9_.-]{0,63}$/u;

/**
 * Return `true` when `target` looks like a board name (starts with `#`).
 */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("#");
}

/**
 * Normalize a raw messaging target into the canonical form understood by
 * PulseBoard, or return `undefined` when the input is not a valid target.
 *
 * Accepted forms:
 *   - `pulseboard:#boardname`  → `#boardname`
 *   - `board:boardname`        → `#boardname`
 *   - `user:alice`             → `alice`
 *   - `#boardname`             → `#boardname`
 *   - `alice`                  → `alice`
 */
export function normalizePulseBoardMessagingTarget(
  raw: string,
): string | undefined {
  const trimmed = raw.trim();
  if (!trimmed) {
    return undefined;
  }

  let target = trimmed;
  const lowered = target.toLowerCase();

  // Strip optional scheme prefix
  if (lowered.startsWith("pulseboard:")) {
    target = target.slice("pulseboard:".length).trim();
  }

  // Handle board: prefix
  if (target.toLowerCase().startsWith("board:")) {
    target = target.slice("board:".length).trim();
    if (!target.startsWith("#")) {
      target = `#${target}`;
    }
  }

  // Handle user: prefix
  if (target.toLowerCase().startsWith("user:")) {
    target = target.slice("user:".length).trim();
  }

  if (!target) {
    return undefined;
  }

  // Validate the bare name (strip leading # for the pattern check)
  const bare = target.startsWith("#") ? target.slice(1) : target;
  if (!bare || !PULSEBOARD_TARGET_PATTERN.test(bare)) {
    return undefined;
  }

  return target;
}

/**
 * Heuristic: does `input` look like a PulseBoard target id?
 */
export function looksLikePulseBoardTargetId(input: string): boolean {
  const trimmed = input.trim();
  if (!trimmed) {
    return false;
  }
  const bare = trimmed.startsWith("#") ? trimmed.slice(1) : trimmed;
  return PULSEBOARD_TARGET_PATTERN.test(bare);
}

/**
 * Normalize an allowlist entry to a canonical lowercase form.
 */
export function normalizePulseBoardAllowEntry(raw: string): string {
  let value = raw.trim().toLowerCase();
  if (!value) {
    return "";
  }
  if (value.startsWith("pulseboard:")) {
    value = value.slice("pulseboard:".length);
  }
  if (value.startsWith("user:")) {
    value = value.slice("user:".length);
  }
  return value.trim();
}

