import { getPulseBoardRuntime } from "./runtime.js";
import {
  normalizePulseBoardMessagingTarget,
  isBoardTarget,
} from "./normalize.js";
import { resolvePulseBoardAccount } from "./types.js";
import type { OpenClawConfig } from "../api.js";

export type SendPulseBoardOptions = {
  cfg?: OpenClawConfig;
  accountId?: string;
  replyToId?: string;
};

export type SendPulseBoardResult = {
  messageId: string;
  target: string;
  channel: "pulseboard";
};

/**
 * Record an outbound activity event, swallowing errors when the runtime
 * has not been initialized yet (e.g. during tests).
 */
function recordOutboundActivity(accountId: string): void {
  try {
    getPulseBoardRuntime().channel.activity.record({
      channel: "pulseboard",
      accountId,
      direction: "outbound",
    });
  } catch (error) {
    if (
      !(error instanceof Error) ||
      error.message !== "PulseBoard runtime not initialized"
    ) {
      throw error;
    }
  }
}

/**
 * Send a text message to PulseBoard.
 *
 * This is a placeholder implementation for the fictional PulseBoard
 * platform. In a real plugin the body of this function would call the
 * PulseBoard HTTP/WebSocket API.
 */
export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts: SendPulseBoardOptions = {},
): Promise<SendPulseBoardResult> {
  const runtime = getPulseBoardRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as OpenClawConfig;
  const account = resolvePulseBoardAccount({
    cfg,
    accountId: opts.accountId,
  });

  if (!account.configured) {
    throw new Error(
      `PulseBoard is not configured for account "${account.accountId}" (need apiKey in channels.pulseboard).`,
    );
  }

  const target = normalizePulseBoardMessagingTarget(to);
  if (!target) {
    throw new Error(`Invalid PulseBoard target: ${to}`);
  }

  const payload = text.trim();
  if (!payload) {
    throw new Error("Message must be non-empty for PulseBoard sends.");
  }

  // --- Fictional send logic ---
  // In a real implementation this would POST to the PulseBoard API:
  //   POST {serverUrl}/v1/boards/{board}/messages   (group)
  //   POST {serverUrl}/v1/dm/{user}/messages         (direct)
  const endpoint = isBoardTarget(target)
    ? `${account.serverUrl}/v1/boards/${encodeURIComponent(target.slice(1))}/messages`
    : `${account.serverUrl}/v1/dm/${encodeURIComponent(target)}/messages`;

  // Simulate a successful response
  const messageId = `pb-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
  void endpoint; // acknowledge the computed endpoint

  recordOutboundActivity(account.accountId);

  return {
    messageId,
    target,
    channel: "pulseboard",
  };
}

