import type { ChannelSetupAdapter } from "openclaw/plugin-sdk/channel-setup";
import type { OpenClawConfig } from "openclaw/plugin-sdk/config-runtime";
import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/routing";
import {
  createTopLevelChannelParsedAllowFromPrompt,
  createTopLevelChannelDmPolicy,
  createStandardChannelSetupStatus,
  mergeAllowFromEntries,
  patchTopLevelChannelConfigSection,
  splitSetupEntries,
} from "openclaw/plugin-sdk/setup";
import type { ChannelSetupDmPolicy } from "openclaw/plugin-sdk/setup";
import type { ChannelSetupWizard } from "openclaw/plugin-sdk/setup";
import { formatDocsLink } from "openclaw/plugin-sdk/setup";
import { resolvePulseBoardAccount } from "./types.js";
import { normalizePulseBoardAllowEntry } from "./normalize.js";

const channel = "pulseboard" as const;

const PULSEBOARD_SETUP_HELP_LINES = [
  "Provide a PulseBoard API key to connect.",
  "Server URL defaults to https://api.pulseboard.example.",
  "Boards are optional — specify board names to auto-join on startup.",
  "Env vars supported: PULSEBOARD_API_KEY, PULSEBOARD_SERVER_URL.",
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

const PULSEBOARD_ALLOW_FROM_HELP_LINES = [
  "Allowlist PulseBoard DMs by username.",
  "Examples:",
  "- alice",
  "- bob",
  "Multiple entries: comma-separated.",
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

function parsePulseBoardAllowFrom(raw: string): {
  entries: string[];
  error?: string;
} {
  const parts = splitSetupEntries(raw);
  const entries: string[] = [];
  for (const part of parts) {
    const normalized = normalizePulseBoardAllowEntry(part);
    if (!normalized) {
      return { entries: [], error: `Invalid PulseBoard username: ${part}` };
    }
    entries.push(normalized);
  }
  return { entries };
}

function parseBoardList(raw: string): {
  boards: string[];
  error?: string;
} {
  const parts = splitSetupEntries(raw);
  const boards: string[] = [];
  for (const part of parts) {
    const name = part.replace(/^#/, "").trim();
    if (!name || !/^[a-zA-Z0-9_][a-zA-Z0-9_.-]{0,63}$/.test(name)) {
      return { boards: [], error: `Invalid board name: ${part}` };
    }
    boards.push(name);
  }
  return { boards: [...new Set(boards)] };
}

const promptPulseBoardAllowFrom = createTopLevelChannelParsedAllowFromPrompt({
  channel,
  defaultAccountId: DEFAULT_ACCOUNT_ID,
  noteTitle: "PulseBoard allowlist",
  noteLines: PULSEBOARD_ALLOW_FROM_HELP_LINES,
  message: "PulseBoard allowFrom",
  placeholder: "alice, bob",
  parseEntries: parsePulseBoardAllowFrom,
  mergeEntries: ({ existing, parsed }) =>
    mergeAllowFromEntries(existing, parsed),
});

const pulseBoardDmPolicy: ChannelSetupDmPolicy = createTopLevelChannelDmPolicy(
  {
    label: "PulseBoard",
    channel,
    policyKey: "channels.pulseboard.dmPolicy",
    allowFromKey: "channels.pulseboard.allowFrom",
    getCurrent: (cfg) =>
      (cfg as { channels?: { pulseboard?: { dmPolicy?: string } } }).channels
        ?.pulseboard?.dmPolicy ?? "pairing",
    promptAllowFrom: promptPulseBoardAllowFrom,
  },
);

export const pulseBoardSetupAdapter: ChannelSetupAdapter = {
  resolveAccountId: () => DEFAULT_ACCOUNT_ID,

  applyAccountName: ({ cfg, name }) =>
    patchTopLevelChannelConfigSection({
      cfg,
      channel,
      patch: name?.trim() ? { name: name.trim() } : {},
    }),

  validateInput: ({ input }) => {
    const typedInput = input as {
      useEnv?: boolean;
      apiKey?: string;
      serverUrl?: string;
      boards?: string;
    };
    if (!typedInput.useEnv) {
      const apiKey = typedInput.apiKey?.trim();
      if (!apiKey) {
        return "PulseBoard requires --api-key or --use-env.";
      }
    }
    if (typedInput.serverUrl?.trim()) {
      try {
        const parsed = new URL(typedInput.serverUrl.trim());
        if (parsed.protocol !== "https:" && parsed.protocol !== "http:") {
          return "Server URL must use http:// or https://.";
        }
      } catch {
        return `Invalid server URL: ${typedInput.serverUrl}`;
      }
    }
    if (typedInput.boards?.trim()) {
      const result = parseBoardList(typedInput.boards);
      if (result.error) {
        return result.error;
      }
    }
    return null;
  },

  applyAccountConfig: ({ cfg, input }) => {
    const typedInput = input as {
      useEnv?: boolean;
      apiKey?: string;
      serverUrl?: string;
      boards?: string;
    };
    const boardResult = typedInput.boards?.trim()
      ? parseBoardList(typedInput.boards)
      : { boards: [] };
    return patchTopLevelChannelConfigSection({
      cfg,
      channel,
      enabled: true,
      clearFields: typedInput.useEnv ? ["apiKey"] : undefined,
      patch: {
        ...(typedInput.useEnv ? {} : { apiKey: typedInput.apiKey?.trim() }),
        ...(typedInput.serverUrl?.trim()
          ? { serverUrl: typedInput.serverUrl.trim() }
          : {}),
        ...(boardResult.boards.length > 0
          ? { boards: boardResult.boards }
          : {}),
      },
    });
  },
};

export const pulseBoardSetupWizard: ChannelSetupWizard = {
  channel,
  resolveAccountIdForConfigure: () => DEFAULT_ACCOUNT_ID,
  resolveShouldPromptAccountIds: () => false,

  status: createStandardChannelSetupStatus({
    channelLabel: "PulseBoard",
    configuredLabel: "configured",
    unconfiguredLabel: "needs API key",
    configuredHint: "configured",
    unconfiguredHint: "needs API key",
    configuredScore: 1,
    unconfiguredScore: 0,
    includeStatusLine: true,
    resolveConfigured: ({ cfg }) =>
      resolvePulseBoardAccount({ cfg }).configured,
    resolveExtraStatusLines: ({ cfg }) => {
      const account = resolvePulseBoardAccount({ cfg });
      const lines: string[] = [];
      if (account.serverUrl) {
        lines.push(`Server: ${account.serverUrl}`);
      }
      if (account.boards.length > 0) {
        lines.push(
          `Boards: ${account.boards.map((b) => `#${b}`).join(", ")}`,
        );
      }
      return lines;
    },
  }),

  introNote: {
    title: "PulseBoard setup",
    lines: PULSEBOARD_SETUP_HELP_LINES,
  },

  envShortcut: {
    prompt: "PULSEBOARD_API_KEY detected. Use env var?",
    preferredEnvVar: "PULSEBOARD_API_KEY",
    isAvailable: ({ cfg, accountId }) =>
      accountId === DEFAULT_ACCOUNT_ID &&
      Boolean(process.env.PULSEBOARD_API_KEY?.trim()) &&
      !resolvePulseBoardAccount({ cfg, accountId }).config.apiKey?.trim(),
    apply: async ({ cfg }) =>
      patchTopLevelChannelConfigSection({
        cfg,
        channel,
        enabled: true,
        clearFields: ["apiKey"],
        patch: {},
      }),
  },

  credentials: [
    {
      inputKey: "apiKey",
      providerHint: channel,
      credentialLabel: "API key",
      preferredEnvVar: "PULSEBOARD_API_KEY",
      helpTitle: "PulseBoard API key",
      helpLines: PULSEBOARD_SETUP_HELP_LINES,
      envPrompt: "PULSEBOARD_API_KEY detected. Use env var?",
      keepPrompt: "PulseBoard API key already configured. Keep it?",
      inputPrompt: "PulseBoard API key",
      allowEnv: ({ accountId }) => accountId === DEFAULT_ACCOUNT_ID,
      inspect: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({ cfg, accountId });
        const configuredValue = account.config.apiKey?.trim() ?? "";
        return {
          accountConfigured: account.configured,
          hasConfiguredValue: Boolean(configuredValue),
          resolvedValue: configuredValue || undefined,
          envValue: process.env.PULSEBOARD_API_KEY?.trim(),
        };
      },
      applyUseEnv: async ({ cfg }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          clearFields: ["apiKey"],
          patch: {},
        }),
      applySet: async ({ cfg, resolvedValue }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          patch: { apiKey: resolvedValue },
        }),
    },
  ],

  textInputs: [
    {
      inputKey: "serverUrl",
      message: "Server URL (optional, defaults to https://api.pulseboard.example)",
      placeholder: "https://api.pulseboard.example",
      required: false,
      applyEmptyValue: true,
      helpTitle: "PulseBoard server URL",
      helpLines: [
        "Enter the base URL of the PulseBoard instance.",
        "Leave blank to use the default (https://api.pulseboard.example).",
      ],
      currentValue: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({ cfg, accountId });
        return account.config.serverUrl?.trim() ?? "";
      },
      keepPrompt: (value) => `Server URL set (${value}). Keep it?`,
      validate: ({ value }) => {
        try {
          const parsed = new URL(value);
          if (parsed.protocol !== "https:" && parsed.protocol !== "http:") {
            return "Server URL must use http:// or https://.";
          }
          return undefined;
        } catch {
          return `Invalid server URL: ${value}`;
        }
      },
      applySet: async ({ cfg, value }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          clearFields: value.trim() ? undefined : ["serverUrl"],
          patch: value.trim() ? { serverUrl: value.trim() } : {},
        }),
    },
