import { describeAccountSnapshot } from "openclaw/plugin-sdk/account-helpers";
import {
  createScopedDmSecurityResolver,
  createTopLevelChannelConfigAdapter,
} from "openclaw/plugin-sdk/channel-config-helpers";
import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";
import {
  buildPassiveChannelStatusSummary,
  buildTrafficStatusSummary,
} from "openclaw/plugin-sdk/extension-shared";
import { createComputedAccountStatusAdapter } from "openclaw/plugin-sdk/status-helpers";
import {
  buildChannelConfigSchema,
  createDefaultChannelRuntimeState,
  DEFAULT_ACCOUNT_ID,
  formatPairingApproveHint,
  type ChannelPlugin,
} from "../runtime-api.js";
import { PulseBoardConfigSchema } from "./config-schema.js";
import {
  normalizePulseBoardMessagingTarget,
  normalizePulseBoardAllowEntry,
  looksLikePulseBoardTargetId,
} from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import { sendMessagePulseBoard } from "./send.js";
import {
  pulseBoardSetupAdapter,
  pulseBoardSetupWizard,
} from "./setup-surface.js";
import {
  listPulseBoardAccountIds,
  resolveDefaultPulseBoardAccountId,
  resolvePulseBoardAccount,
  type ResolvedPulseBoardAccount,
} from "./types.js";

const pulseBoardConfigAdapter =
  createTopLevelChannelConfigAdapter<ResolvedPulseBoardAccount>({
    sectionKey: "pulseboard",
    resolveAccount: (cfg) => resolvePulseBoardAccount({ cfg }),
    listAccountIds: listPulseBoardAccountIds,
    defaultAccountId: resolveDefaultPulseBoardAccountId,
    deleteMode: "clear-fields",
    clearBaseFields: [
      "name",
      "defaultAccount",
      "apiKey",
      "serverUrl",
      "boards",
      "dmPolicy",
      "allowFrom",
    ],
    resolveAllowFrom: (account) => account.config.allowFrom,
    formatAllowFrom: (allowFrom) =>
      allowFrom
        .map((entry) => normalizePulseBoardAllowEntry(String(entry)))
        .filter(Boolean),
  });

const resolvePulseBoardDmPolicy =
  createScopedDmSecurityResolver<ResolvedPulseBoardAccount>({
    channelKey: "pulseboard",
    resolvePolicy: (account) => account.config.dmPolicy,
    resolveAllowFrom: (account) => account.config.allowFrom,
    policyPathSuffix: "dmPolicy",
    defaultPolicy: "pairing",
    approveHint: formatPairingApproveHint("pulseboard"),
    normalizeEntry: (raw) => normalizePulseBoardAllowEntry(raw),
  });

export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> =
  createChatChannelPlugin({
    base: {
      id: "pulseboard",
      meta: {
        id: "pulseboard",
        label: "PulseBoard",
        selectionLabel: "PulseBoard",
        docsPath: "/channels/pulseboard",
        docsLabel: "pulseboard",
        blurb:
          "Real-time bulletin board messaging with boards and direct messages.",
        order: 110,
      },
      capabilities: {
        chatTypes: ["direct", "group"],
        media: false,
      },
      reload: { configPrefixes: ["channels.pulseboard"] },
      configSchema: buildChannelConfigSchema(PulseBoardConfigSchema),
      setup: pulseBoardSetupAdapter,
      setupWizard: pulseBoardSetupWizard,
      config: {
        ...pulseBoardConfigAdapter,
        isConfigured: (account) => account.configured,
        describeAccount: (account) =>
          describeAccountSnapshot({
            account,
            configured: account.configured,
            extra: {
              serverUrl: account.serverUrl,
              boards: account.boards.length > 0 ? account.boards : undefined,
            },
          }),
      },
      messaging: {
        normalizeTarget: (target) =>
          normalizePulseBoardMessagingTarget(target),
        targetResolver: {
          looksLikeId: looksLikePulseBoardTargetId,
          hint: "<#board|username>",
        },
      },
      status: {
        ...createComputedAccountStatusAdapter<ResolvedPulseBoardAccount>({
          defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
          buildChannelSummary: ({ snapshot }) =>
            buildPassiveChannelStatusSummary(snapshot, {
              serverUrl: snapshot.serverUrl ?? null,
            }),
          resolveAccountSnapshot: ({ account, runtime }) => ({
            accountId: account.accountId,
            name: account.name,
            enabled: account.enabled,
            configured: account.configured,
            extra: {
              serverUrl: account.serverUrl,
              boards: account.boards,
              ...buildTrafficStatusSummary(runtime),
            },
          }),
        }),
      },
      gateway: {
        startAccount: async (ctx) => {
          const account = ctx.account;
          ctx.setStatus({ accountId: account.accountId });
          ctx.log?.info(
            `[${account.accountId}] starting PulseBoard provider (server: ${account.serverUrl})`,
          );

          if (!account.configured) {
            throw new Error("PulseBoard API key not configured");
          }

          // Placeholder: a real implementation would open a WebSocket
          // connection to the PulseBoard server and subscribe to the
          // configured boards here.

          ctx.log?.info(
            `[${account.accountId}] PulseBoard provider started, ` +
              `subscribed to ${account.boards.length} board(s)`,
          );

          return {
            stop: () => {
              ctx.log?.info(
                `[${account.accountId}] PulseBoard provider stopped`,
              );
            },
          };
        },
      },
    },
    pairing: {
      text: {
        idLabel: "pulseBoardUser",
        message: "Your pairing request has been approved!",
        normalizeAllowEntry: (entry) => normalizePulseBoardAllowEntry(entry),
        notify: async ({ id, message }) => {
          // In a real plugin this would send a DM to the user via the
          // PulseBoard API. Placeholder for the fictional platform.
          void id;
          void message;
        },
      },
    },
    security: {
      resolveDmPolicy: resolvePulseBoardDmPolicy,
    },
    outbound: {
      deliveryMode: "direct",
      textChunkLimit: 4000,
      sendText: async ({ cfg, to, text, accountId }) => {
        const result = await sendMessagePulseBoard(to, text ?? "", {
          cfg: cfg as ReturnType<typeof getPulseBoardRuntime>["config"] extends {
            loadConfig: () => infer C;
          }
            ? C
            : never,
          accountId: accountId ?? undefined,
        });
        return attachChannelToResult("pulseboard", {
          to: result.target,
          messageId: result.messageId,
        });
      },
      sendMedia: async ({ cfg, to, text, mediaUrl, accountId }) => {
        // PulseBoard does not support native media uploads; append the URL
        // as a text link instead.
        const body = mediaUrl ? `${text ?? ""}\n\nAttachment: ${mediaUrl}` : (text ?? "");
        const result = await sendMessagePulseBoard(to, body, {
          cfg: cfg as ReturnType<typeof getPulseBoardRuntime>["config"] extends {
            loadConfig: () => infer C;
          }
            ? C
            : never,
          accountId: accountId ?? undefined,
        });
        return attachChannelToResult("pulseboard", {
          to: result.target,
          messageId: result.messageId,
        });
      },
    },
  });

